import{c as t,Q as o,j as i,m as r}from"./chunks/framework.CdiUUa3G.js";const p=JSON.parse('{"title":"PRD-018 · Image Pipeline v2 — vision-model scoring + smart cropping","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-018.md","filePath":"prd/PRD-018.md"}'),a={name:"prd/PRD-018.md"};function s(n,e,d,c,l,g){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="prd-018-·-image-pipeline-v2-—-vision-model-scoring-smart-cropping" tabindex="-1">PRD-018 · Image Pipeline v2 — vision-model scoring + smart cropping <a class="header-anchor" href="#prd-018-·-image-pipeline-v2-—-vision-model-scoring-smart-cropping" aria-label="Permalink to &quot;PRD-018 · Image Pipeline v2 — vision-model scoring + smart cropping&quot;">​</a></h1><blockquote><p>Status · Draft v0.4 (all 4 v2.0 architectural decisions resolved 2026-05-16) Date · 2026-05-16 Owner · Marko Closes into · RFC-022 Slice gate · v1.x (after PRD-015 mobile + PRD-016 audio + PRD-017 sensory)</p></blockquote><blockquote><p><strong>Why this is a PRD.</strong> The decision to add vision-model scoring + smart cropping to the asset pipeline changes the cost model (paid Anthropic Vision API calls per build, ~$67 first-build / ~$0 cached), the build duration (sharp pre-cropping at 3 aspect ratios for ~1100 curated images = real CI minutes), the editorial trust model (model-picked vs human-picked imagery), and the mobile bundle (smart-crop variants shave ~30 MB off the fleet-gallery bucket). It is <strong>purely additive</strong> — the existing <code>image-provenance.json</code> (ADR-047, 1345 entries) stays untouched, the existing curation flow is preserved, and the v2 layer is a new sidecar that can be backed out without breaking what ships today.</p></blockquote><hr><h2 id="§why" tabindex="-1">§why <a class="header-anchor" href="#§why" aria-label="Permalink to &quot;§why&quot;">​</a></h2><p>The current image pipeline (<code>scripts/fetch-assets.ts</code> + ADR-016 + ADR-046 + ADR-047) ships 1345 provenance-tracked images. It works — every image has a license, a credit, a last-verified date, and is enforced by <code>validate-data.ts</code> as a fail-closed gate. The system is healthy.</p><p>What it <strong>does not</strong> do: tell us anything about the <em>visual content</em> of the images. Two specific failure modes recur in PR review:</p><ol><li><strong>Wrong image picked.</strong> A NASA Images API result returns a press conference photo when we wanted Curiosity on Mars. The metadata search ranks by tags, not by what&#39;s in the frame. We catch these by hand; we miss some.</li><li><strong>Right image, wrong crop.</strong> A clean wide-shot of a spacecraft has the spacecraft in the right third. CSS <code>object-fit: cover</code> with default centred <code>object-position</code> chops the spacecraft off. Subject lost.</li></ol><p>PRD-018 / RFC-022 fix both at build time, without touching the provenance pipeline that already works. The v2 layer adds:</p><ul><li><strong>Per-image vision-API scoring</strong> (Claude Sonnet 4.6) — each image gets a 1-10 score, a one-sentence subject description, a category (one of nine), and a focal-point coordinate (x, y as 0.0–1.0).</li><li><strong>Smart-crop variants</strong> — at build time, <code>sharp</code> generates 1:1 + 4:3 + 16:9 pre-cropped variants using the focal point as the crop anchor. Three variants per source image; mobile build picks 1:1 for fleet galleries, web picks 16:9 for hero, 4:3 for cards.</li><li><strong>A new sidecar manifest</strong> — <code>static/data/image-vision.json</code> keyed by image path. Joins to <code>image-provenance.json</code> (ADR-047) at runtime; never modifies it. Backing out v2 = deleting the sidecar; the existing image pipeline keeps working.</li></ul><p><strong>This is evolution, not replacement.</strong> Per Marko&#39;s directive: &quot;evolution of what we have now, not to change anything unless we&#39;re evolving, so a new layer on.&quot; ADR-047 stays. The sidecar is the new layer.</p><hr><h2 id="§audiences" tabindex="-1">§audiences <a class="header-anchor" href="#§audiences" aria-label="Permalink to &quot;§audiences&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Audience</th><th>Why this helps them</th></tr></thead><tbody><tr><td>Curious learner</td><td>Mission galleries actually show what they came to see. The hero crop on <code>/missions/curiosity</code> shows the rover, not a press photo of an admin office.</td></tr><tr><td>Educator / journalist</td><td>Reliable visual-quality bar across the corpus. Cite an Orrery page knowing the imagery isn&#39;t accidental.</td></tr><tr><td>Editor / curator (Marko)</td><td>Fewer manual review iterations. Audit-report HTML surfaces every candidate the model considered + the score that picked the winner. Easy to spot a bad pick and tune the prompt.</td></tr><tr><td>Mobile audience (post PRD-015)</td><td>~30 MB lighter Capacitor bundle thanks to 1:1 pre-cropped fleet-gallery variants. Fits inside the ~85 MB target with headroom.</td></tr></tbody></table><hr><h2 id="§what-s-already-shipped-image-pipeline-readiness-inventory" tabindex="-1">§what&#39;s already shipped (image-pipeline-readiness inventory) <a class="header-anchor" href="#§what-s-already-shipped-image-pipeline-readiness-inventory" aria-label="Permalink to &quot;§what&#39;s already shipped (image-pipeline-readiness inventory)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Capability</th><th>Status</th><th>Source</th></tr></thead><tbody><tr><td><code>scripts/fetch-assets.ts</code> (NASA Images API + Wikimedia + agency portals fetch)</td><td>shipped</td><td>ADR-016 (build-time asset resolution)</td></tr><tr><td><code>static/data/image-provenance.json</code> (1345 entries, license + credit + last-verified)</td><td>shipped</td><td>ADR-046 + ADR-047</td></tr><tr><td><code>validate-data.ts</code> enforces image provenance integrity (fail-closed gate)</td><td>shipped</td><td>ADR-047 Milestone C</td></tr><tr><td>Asset-size cap (8 MiB per image, workbox precache cap)</td><td>shipped</td><td>validate-data.ts</td></tr><tr><td>Mission galleries render via runtime fetch from NASA Images API</td><td>shipped (but a v2 candidate to remove — see M4)</td><td>gallery components</td></tr><tr><td>Hero photos use CSS <code>object-fit: cover</code> with default centred <code>object-position</code></td><td>shipped (but the failure mode v2 fixes — see M2)</td><td>hero components</td></tr><tr><td>MOBILE=1 build env (lazy locales + thumbnail tier per RFC-018 §4)</td><td>planned (v0.8)</td><td>RFC-018 §4</td></tr></tbody></table><hr><h2 id="§goal" tabindex="-1">§goal <a class="header-anchor" href="#§goal" aria-label="Permalink to &quot;§goal&quot;">​</a></h2><p>Ship a vision-pipeline v2 layer that runs at build time, joins to the existing provenance manifest by image path, and produces per-image scoring + focal-point + smart-crop variants for <strong>every image in the corpus</strong> (~1345 entries). Frontend renders use the new manifest for object-position + variant selection; v2 layer can be backed out by deleting the sidecar without breaking anything else.</p><p><strong>v2.0 ship gate</strong> = scoring + focal-point + sharp pre-cropping (1:1 + 4:3 + 16:9) + frontend integration + audit report HTML.</p><p><strong>v2.1</strong> = multi-source candidate pool (extend <code>fetch-assets.ts</code> to ESA + JAXA + ROSCOSMOS portals beyond NASA + Wikimedia).</p><p><strong>v2.2</strong> = manual override UI (operator-tuned scoring overrides for edge cases the model gets wrong).</p><hr><h2 id="§user-stories" tabindex="-1">§user stories <a class="header-anchor" href="#§user-stories" aria-label="Permalink to &quot;§user stories&quot;">​</a></h2><p><strong>US-1 — Editorial trust on hero images.</strong> A visitor opens <code>/missions/curiosity</code> and the hero image is unmistakably Curiosity on Mars. Not a press conference; not a diagram. The vision pipeline rejected the press photo at score &lt; 5.</p><p><strong>US-2 — Subject preserved across aspect ratios.</strong> A wide-shot of Saturn V is centred on the rocket, not on empty sky to the left. Hero (16:9) shows the rocket in the centre third; gallery card (4:3) shows it framed; mobile thumbnail (1:1) is tightly cropped on the rocket&#39;s middle stage. All three crops use the same focal point from the vision API.</p><p><strong>US-3 — Mobile bundle savings.</strong> The Capacitor build (PRD-015 / RFC-018) bundles the 1:1 pre-cropped variants of fleet-gallery images at ~256 px instead of the full hero quality. ~30 MB saved off the existing 120 MB fleet-gallery bucket on mobile.</p><p><strong>US-4 — Editor audit loop.</strong> Marko runs <code>npm run images:audit-report</code>, opens <code>audit-report.html</code> (gitignored), and sees every candidate per mission with: thumbnail, score, category, subject, focal-point crosshair, selection status, reject reason if rejected. Spots a bad pick → adjusts the <code>gallery_query</code> for that mission → re-runs the pipeline → cache hits everywhere except the changed query.</p><p><strong>US-5 — Build-time only, zero runtime API exposure.</strong> Anthropic Vision API key never reaches the browser. All scoring happens at build. Frontend reads the static <code>image-vision.json</code> sidecar.</p><p><strong>US-6 — &quot;This image is bad&quot; — human-feedback curation loop.</strong> From the audit report, Marko clicks a &quot;flag&quot; button on any image, types a reason (&quot;subject is occluded by hardware caption&quot;, &quot;wrong rover&quot;, &quot;looks like a render&quot;), and the image is added to a curation deny-list (<code>static/data/image-curation.json</code>). Subsequent pipeline runs treat that image as <code>score: 0, rejected_by: &quot;human&quot;</code>. The flag + reason feed back into the scoring prompt as an <strong>example</strong> (&quot;avoid this kind of result, see deny-list reason X&quot;) so the model learns Marko&#39;s editorial preferences over time without retraining.</p><p><strong>US-7 — Granular pipeline scoping.</strong> Marko runs the pipeline against subsets, not always the full corpus: <code>--mission curiosity</code>, <code>--agency NASA</code>, <code>--source nasa-images-api</code>, <code>--fleet-asset crew-portraits</code>, <code>--segment fleet-galleries</code>. Each subset reuses the cache for everything outside the subset; inside the subset, scoring + cropping re-runs (or stays cached if hash-unchanged). Full rebuild (<code>--all</code>) is the catch-all but never the default. Cost-per-iteration drops from $67 → $0.50 when iterating on a single mission.</p><hr><h2 id="§must-have-requirements" tabindex="-1">§must-have requirements <a class="header-anchor" href="#§must-have-requirements" aria-label="Permalink to &quot;§must-have requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Requirement</th></tr></thead><tbody><tr><td><strong>M1</strong></td><td>Vision-API scoring at build time. Claude <strong>Sonnet 4.6</strong> (<code>claude-sonnet-4-6</code>) scores every image candidate. Returns: <code>score</code> (1-10), <code>subject</code> (one sentence), <code>category</code> (one of: <code>spacecraft</code> / <code>surface</code> / <code>launch</code> / <code>orbital</code> / <code>hardware</code> / <code>people</code> / <code>diagram</code> / <code>render</code> / <code>other</code>), <code>focal_point</code> ({ x: 0.0-1.0, y: 0.0-1.0 }), <code>reject_reason</code> (string or null).</td></tr><tr><td><strong>M2</strong></td><td>Selection threshold: <code>score &gt;= 5</code> AND category not in {<code>people</code>, <code>diagram</code>} for general use. Status-aware: PLANNED missions accept <code>render</code> (5-7 acceptable). FLOWN/ACTIVE missions reject <code>render</code> outright.</td></tr><tr><td><strong>M3</strong></td><td>Hero + gallery selection algorithm: hero = highest-scoring <code>spacecraft</code> or <code>surface</code> candidate (or fallback to highest non-rejected). Gallery = next 8 by score, with category diversity (max 4 per category in 9-image gallery).</td></tr><tr><td><strong>M4</strong></td><td>Smart-crop variants generated at build time via <code>sharp</code>. Three variants per source image: <code>1:1</code> (square, mobile thumbnails), <code>4:3</code> (gallery cards), <code>16:9</code> (hero). Crop anchor = <code>focal_point</code> from vision API. Each variant is a separate file: <code>{base}.1x1.jpg</code>, <code>{base}.4x3.jpg</code>, <code>{base}.16x9.jpg</code>. Source image kept (used for full-quality lightbox).</td></tr><tr><td><strong>M5</strong></td><td>New sidecar manifest: <code>static/data/image-vision.json</code>. Schema: <code>{ &quot;&lt;image-path&gt;&quot;: { score, subject, category, focal_point, variants: { &quot;1x1&quot;: &quot;...&quot;, &quot;4x3&quot;: &quot;...&quot;, &quot;16x9&quot;: &quot;...&quot; } } }</code>. Joins to <code>image-provenance.json</code> by image-path key. <strong>Does not modify image-provenance.json.</strong></td></tr><tr><td><strong>M6</strong></td><td><code>validate-data.ts</code> gains a NEW OPTIONAL check: if a v2-scored image lacks a manifest entry, log a warning (not a fail). Fail-closed only if <code>image-vision.json</code> exists but is malformed. The existing fail-closed image-provenance gate stays unchanged.</td></tr><tr><td><strong>M7</strong></td><td>Hash-based cache. Per-image cache key = SHA-256 of (source-image-bytes + scoring-prompt-version). Per-variant cache key = SHA-256 of (source-image-bytes + crop-spec). Cache lives at <code>.image-cache/</code> (gitignored). Unchanged source + unchanged prompt = no API call, no re-crop.</td></tr><tr><td><strong>M8</strong></td><td>Build-time budget: full cache-cold rebuild &lt; 30 minutes wall clock on Marko&#39;s M-series Mac. Cache-warm rebuild &lt; 60 seconds. Per-image cost ~$0.05 (Sonnet) → ~$67 first build for 1345 images, ~$0 cached builds.</td></tr><tr><td><strong>M9</strong></td><td>Frontend reads <code>image-vision.json</code> at build time (Vite static import). Hero / card / thumbnail components select the correct variant by container aspect ratio + viewport. Mobile (PRD-015 wrapper) picks 1:1 for fleet galleries; desktop picks 4:3 for cards + 16:9 for hero.</td></tr><tr><td><strong>M10</strong></td><td>Runtime NASA Images API calls <strong>eliminated</strong> for any view served by <code>image-vision.json</code>. Gallery fully offline from manifest + bundled images. Removes the &quot;LIVE&quot; indicator from the gallery component.</td></tr><tr><td><strong>M11</strong></td><td><code>ANTHROPIC_API_KEY</code> setup is a documented v2.0 prerequisite. <strong>Anthropic API is NOT covered by Claude Code subscription</strong> (announced 2026-05) — v2 needs its own paid API access. Setup: GitHub Actions secret + local <code>~/.zshrc</code> export or <code>.env.local</code>. Same key as PRD-016 audio pipeline (Anthropic billing is per-account). Documented in <code>docs/guides/image-pipeline-v2.md</code>. Auth failures don&#39;t fail the build (M13 fallback applies).</td></tr><tr><td><strong>M12</strong></td><td>Audit report HTML auto-generated on every scoring run: <code>static/audit-report.html</code> (gitignored — dev-only). Shows every candidate per image with: thumbnail at 192 px, score, category, subject, focal-point crosshair, selection status, reject reason if rejected. Marko opens locally to spot tuning opportunities.</td></tr><tr><td><strong>M13</strong></td><td>Fallback behaviour: zero-acceptable-images for an image slot → use highest-scoring candidate regardless of threshold + flag with <code>&quot;fallback&quot;: true</code> in manifest entry. Build never fails closed because of a vision-API call result. API outage during build → fall back to last cached scores; build continues.</td></tr><tr><td><strong>M14</strong></td><td>Per-image processing is idempotent. Running the pipeline twice with no source changes produces a byte-identical <code>image-vision.json</code> and byte-identical variant files.</td></tr><tr><td><strong>M15</strong></td><td><strong>Human curation deny-list.</strong> A new sidecar <code>static/data/image-curation.json</code> (committed to the repo) lists images Marko has flagged as bad, each with a one-line reason. Pipeline reads on every run; flagged images are scored as <code>score: 0, rejected_by: &quot;human&quot;</code> regardless of model output. The deny-list survives cache rebuilds.</td></tr><tr><td><strong>M16</strong></td><td><strong>Curation feedback loop in scoring prompt.</strong> The vision-API prompt includes the most recent ~5 deny-list entries as in-context examples (&quot;avoid: subject occluded by caption / wrong rover / looks like a render&quot;). Updates Marko&#39;s editorial bar over time without re-training the model. Deny-list size capped at 100 entries — older entries rotate out of the prompt context but stay in the deny-list.</td></tr><tr><td><strong>M17</strong></td><td><strong>Audit report flag UI.</strong> The audit-report HTML has a &quot;🚩 Flag this image&quot; button on each candidate. Click → opens a small form to enter a reason → POSTs to a tiny <code>scripts/flag-image.ts</code> helper that appends to <code>image-curation.json</code>. The audit-report is HTML-only (no server); the helper runs as <code>node scripts/flag-image.ts</code> from a clipboard payload. Operator workflow: click flag → reason copied to clipboard → run helper → commit.</td></tr><tr><td><strong>M18</strong></td><td><strong>Granular pipeline scoping flags.</strong> CLI supports: <code>--mission &lt;id&gt;</code>, <code>--agency &lt;name&gt;</code> (NASA / ESA / JAXA / ROSCOSMOS / CNSA / ISRO), <code>--source &lt;name&gt;</code> (nasa-images-api / wikimedia-commons / agency-portal-* / curated-url), <code>--fleet-asset &lt;type&gt;</code> (heroes / patches / portraits / galleries), <code>--segment &lt;name&gt;</code> (mission-galleries / fleet / agency-logos / science-diagrams / planet-textures), <code>--new-only</code> (process only entries that don&#39;t yet have a manifest record OR whose hash inputs changed), <code>--changed-since &lt;git-ref&gt;</code> (process only entries whose source files were modified since the given git ref), <code>--all</code> (catch-all, full corpus). Subsets reuse cache outside their scope; inside their scope, scoring + cropping re-runs unless hash-unchanged.</td></tr><tr><td><strong>M19</strong></td><td><strong>Default CLI behaviour = incremental.</strong> Running <code>npm run images:score</code> with no flags is equivalent to <code>--new-only</code>: scans <code>image-provenance.json</code> for entries missing from <code>image-vision.json</code> (or whose hash inputs changed) and processes only those. Routine workflow (&quot;I added new images, run the pipeline&quot;) costs $0–$5 per run, never $67. Cost discipline is preserved — <code>--all</code> is now the explicit opt-in for &quot;re-score the whole corpus&quot; (used after a prompt-rubric change or model swap).</td></tr><tr><td><strong>M20</strong></td><td><strong>Architectural guarantee — never reprocess unchanged entries.</strong> Cache invalidation triggers are EXPLICIT and finite: (a) source image bytes change, (b) <code>scoring_prompt_version</code> constant bumps, (c) <code>vision_model</code> config string changes, (d) image is added to <code>image-curation.json</code>, (e) <code>sharp</code> major version upgrades (variant cache only). Time-based invalidation (e.g. &quot;re-score everything monthly&quot;) is explicitly NOT a trigger. Routine builds must be effectively free for unchanged entries.</td></tr><tr><td><strong>M21</strong></td><td>Single-mission iteration cost: <code>--mission curiosity</code> scores ≤ 15 images at ~$0.05 each = ≤ $0.75 per iteration. Single-agency iteration: <code>--agency JAXA</code> scores ~80 images = ~$4. Whole corpus (<code>--all</code>): ~$67 first build, ~$0 cached. Incremental default (<code>--new-only</code> implicit): $0 if nothing changed, $0.05–$5 typical when a few entries land.</td></tr></tbody></table><hr><h2 id="§should-have-requirements" tabindex="-1">§should-have requirements <a class="header-anchor" href="#§should-have-requirements" aria-label="Permalink to &quot;§should-have requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Requirement</th></tr></thead><tbody><tr><td><strong>S1</strong></td><td><code>--mission &lt;id&gt;</code> flag on the pipeline CLI to score / re-crop a single mission&#39;s images only (faster iteration loop).</td></tr><tr><td><strong>S2</strong></td><td><code>--force-score</code> flag to invalidate the scoring cache (re-run vision API even on cached entries — useful when prompt is updated).</td></tr><tr><td><strong>S3</strong></td><td><code>--skip-scoring</code> flag to run only the variant-cropping path on existing scores (useful when only the crop logic changed).</td></tr><tr><td><strong>S4</strong></td><td>Scoring telemetry: every API call logged to <code>static/data/image-vision-cost-ledger.json</code> (similar shape to PRD-016 audio cost ledger). Tracks per-build $ spend; threshold soft-warn at $50/build, hard-halt at $200/build.</td></tr><tr><td><strong>S5</strong></td><td>Audit report shows per-image cost ledger entries inline so Marko can see &quot;this build spent $0.45 on 9 candidates for this mission.&quot;</td></tr></tbody></table><hr><h2 id="§will-not-have-v2-0" tabindex="-1">§will-not-have (v2.0) <a class="header-anchor" href="#§will-not-have-v2-0" aria-label="Permalink to &quot;§will-not-have (v2.0)&quot;">​</a></h2><ul><li><strong>Manual override UI.</strong> Deferred to v2.2.</li><li><strong>Multi-source candidate pool beyond NASA + Wikimedia.</strong> ESA / JAXA / ROSCOSMOS portal scrapers deferred to v2.1.</li><li><strong>Video scoring.</strong> Out of scope; videos remain human-curated.</li><li><strong>Texture / logo / agency-asset scoring.</strong> These are static, human-picked, and don&#39;t benefit from vision scoring.</li><li><strong>Per-user image-quality preferences.</strong> No runtime user knobs; the build picks the variant by container aspect ratio.</li><li><strong>Cropping the source images in-place.</strong> Variants are NEW files; the source survives untouched (lightbox + future re-crop).</li><li><strong>Modifying <code>image-provenance.json</code> schema.</strong> Per Marko&#39;s &quot;evolution, new layer on&quot; directive. ADR-047 stays untouched.</li><li><strong>Replacing <code>validate-data.ts</code>&#39;s existing fail-closed image-provenance check.</strong> That gate stays as-is; v2 adds an OPTIONAL check.</li></ul><hr><h2 id="§success-criteria" tabindex="-1">§success-criteria <a class="header-anchor" href="#§success-criteria" aria-label="Permalink to &quot;§success-criteria&quot;">​</a></h2><p><strong>Editorial:</strong></p><ol><li>≥ 90 % of mission hero images post-v2 show the relevant spacecraft/surface (verified by Marko + 1 reviewer pass on all 30 missions).</li><li>≤ 5 % of gallery images post-v2 are categorised <code>people</code> or <code>diagram</code> (manifest-level audit).</li><li>≥ 85 % of mission hero images render with the focal subject inside the visible crop area at the desktop hero aspect ratio (16:9).</li></ol><p><strong>Technical:</strong> 4. First-build cache-cold rebuild &lt; 30 min; cached rebuild &lt; 60 s. 5. First-build cost ≤ $80 (sized for ~1345 entries on Sonnet 4.6 with 5 % overhead). 6. Mobile (Capacitor) fleet-gallery bucket drops from ~120 MB → ~90 MB (target ~30 MB savings via 1:1 pre-cropped variants). 7. No regression in PRD-015 M11 ceiling (~150 MB Capacitor install). 8. <code>validate-data.ts</code> continues to enforce ADR-047 image-provenance integrity unchanged.</p><p><strong>Operational:</strong> 9. Marko can <code>npm run images:audit-report</code> + open the HTML in browser within 10 s. 10. Single-mission re-score <code>--mission curiosity --force-score</code> completes in &lt; 2 minutes including API calls + sharp variant generation.</p><hr><h2 id="§dependencies" tabindex="-1">§dependencies <a class="header-anchor" href="#§dependencies" aria-label="Permalink to &quot;§dependencies&quot;">​</a></h2><ul><li><strong>PRD-015 / RFC-018 (mobile wrapper)</strong> must exist for the mobile-bundle savings (M9 + success criterion #6) to materialise. v2.0 ships independently; mobile benefit lands when the Capacitor build picks 1:1 variants.</li><li><strong>ADR-016 (build-time asset resolution)</strong> — v2.0 strictly respects: zero runtime third-party API calls.</li><li><strong>ADR-046 (asset pipeline) + ADR-047 (image-provenance manifest)</strong> — v2.0 leaves untouched. Sidecar joins by image-path key.</li><li><strong>Anthropic API SDK in build chain</strong> — <code>@anthropic-ai/sdk</code> added as devDependency.</li><li><strong><code>sharp</code></strong> — added as devDependency for build-time variant generation.</li></ul><hr><h2 id="§resolved-decisions" tabindex="-1">§resolved decisions <a class="header-anchor" href="#§resolved-decisions" aria-label="Permalink to &quot;§resolved decisions&quot;">​</a></h2><p><em>Resolved 2026-05-16 in conversation with Marko.</em></p><ol><li><strong>Manifest model — RESOLVED: New sidecar layer (<code>static/data/image-vision.json</code>) joining to <code>image-provenance.json</code> by image-path key.</strong> ADR-047 untouched. Per Marko&#39;s &quot;evolution, new layer on&quot; directive. Vision pipeline can be backed out by deleting the sidecar without breaking anything else.</li><li><strong>Vision model — RESOLVED: Claude Sonnet 4.6</strong> (<code>claude-sonnet-4-6</code>). Most accurate at subject/category/focal-point. ~$0.05/image; ~$67 first build for 1345 entries; ~$0 cached.</li><li><strong>Corpus scope — RESOLVED: Whole corpus (1345 image-provenance entries).</strong> Maximum editorial coverage. First-build cost accepted.</li><li><strong>Smart-crop variants — RESOLVED: Pull into v2.0</strong> (1:1 + 4:3 + 16:9 via <code>sharp</code> at build time). Mobile bundle savings land immediately (~30 MB off fleet-gallery bucket). v2.0 is bigger, but lands the architectural value.</li><li><strong>Human curation feedback loop — RESOLVED: New sidecar <code>image-curation.json</code> (committed) + scoring prompt includes recent deny-list entries as in-context examples.</strong> Marko flags via audit-report → reason captured → next pipeline run treats image as <code>score: 0, rejected_by: &quot;human&quot;</code> AND the model sees Marko&#39;s editorial bar in the prompt. Closes US-6.</li><li><strong>Granular pipeline scoping — RESOLVED: 6 explicit CLI flags</strong> (<code>--mission</code>, <code>--agency</code>, <code>--source</code>, <code>--fleet-asset</code>, <code>--segment</code>, <code>--all</code>). No implicit default; operator picks scope. Iteration cost drops from $67 (full) to $0.50 (single mission). Closes US-7.</li></ol><hr><h2 id="§open-questions" tabindex="-1">§open questions <a class="header-anchor" href="#§open-questions" aria-label="Permalink to &quot;§open questions&quot;">​</a></h2><ol start="5"><li><strong>Score threshold calibration — confirm <code>&gt;= 5</code>?</strong> Original draft proposed it. After first scoring pass, Marko reviews the distribution + adjusts. Implementation-time decision.</li><li><strong>PRD-016 audio asset hosting parallel — does the vision sidecar live in <code>static/data/</code> (alongside <code>image-provenance.json</code>) or in a new <code>static/data/vision/</code> subdirectory?</strong> Recommend <code>static/data/image-vision.json</code> flat (matches existing convention).</li><li><strong><code>@anthropic-ai/sdk</code> version + token-counting accuracy</strong> — Sonnet 4.6 is current as of 2026-05; verify SDK version supports it (likely <code>&gt;=0.30.0</code>). Implementation-time check.</li><li><strong>CI cost-cap policy.</strong> What&#39;s the per-CI-run hard cap? PRD-016 baked $50/$200; this v2 inherits the same cost ledger pattern. Confirm same thresholds apply or set tighter for image-vision specifically (since first build can hit $67 alone).</li><li><strong>Audit report retention.</strong> v2.0 auto-generates <code>static/audit-report.html</code> per scoring run. Should we retain a history (last 10 builds for diff) or always overwrite? Recommend overwrite for v1, history in v2.1.</li></ol><hr><p><em>PRD-018 · Orrery · Image Pipeline v2 · Drafted 2026-05-16 · Closes-into-RFC-022</em></p>',59)])])}const u=t(a,[["render",s]]);export{p as __pageData,u as default};
